INF(@spec-author>@spec-reader): #Specification{
  name:"TicTacToe",
  version:"1.0",

  types:{
    #Player{value:["X" | "O"]},

    #Cell{value:[#Player | _]},

    #Board{
      cells:[
        #Cell, #Cell, #Cell,
        #Cell, #Cell, #Cell,
        #Cell, #Cell, #Cell
      ],
      indices:0..8,
      shape:{rows:3, cols:3}
    },

    #GameState{
      board:#Board,
      turn:#Player,
      move_count:0..9,
      status:[#ongoing | #won{winner:#Player} | #draw]
    }
  },

  rules:{
    valid_move:{
      preconditions:[
        cell_is_empty($board, $idx) <- board.cells[$idx] = _,
        game_is_ongoing($state) <- $state.status = #ongoing,
        idx_in_range($idx) <- $idx >= 0 & $idx <= 8
      ],
      effect:set_cell($board, $idx, $state.turn) -> toggle_turn($state)
    },

    win_lines:[
      [0,1,2], [3,4,5], [6,7,8],
      [0,3,6], [1,4,7], [2,5,8],
      [0,4,8], [2,4,6]
    ],

    win_condition:
      line_matches($board, $player, $line) <-
        board.cells[$line[0]] = $player &
        board.cells[$line[1]] = $player &
        board.cells[$line[2]] = $player,

    draw_condition:
      is_draw($state) <-
        $state.move_count = 9 &
        ~exists($player, $line: line_matches($state.board, $player, $line))
  },

  functions:{
    check_winner:($board) -> (
      find_first($player: ["X","O"],
        find_first($line: win_lines,
          line_matches($board, $player, $line) -> #Player{value:$player}
        )
      ) | _
    ),

    game_over:($state) -> (
      check_winner($state.board) -> #won{winner:$result}
      | is_draw($state) -> #draw
      | #ongoing
    ),

    is_terminal:($state) -> (
      game_over($state) != #ongoing
    ),

    next_state:($state, $idx) -> (
      valid_move($state, $idx) &
        #GameState{
          board:set_cell($state.board, $idx, $state.turn),
          turn:["X"->"O" | "O"->"X"][$state.turn],
          move_count:$state.move_count + 1,
          status:game_over(set_cell($state.board, $idx, $state.turn))
        }
    )
  },

  invariants:[
    "Each cell holds exactly one Player value or is empty (_)",
    "move_count = count(non-empty cells in board)",
    "Players alternate turns; X moves first",
    "No moves permitted when status != #ongoing",
    "move_count in 0..9 at all times"
  ]
}
