INF(@spec-author>@receiver): #BankingSystemSpec{
  version:"1.0",
  domain:#banking,

  types:[
    #Account{
      id:String,
      owner:String,
      balance:Number,
      currency:String,
      status:#active | #frozen | #closed
    },
    #Transaction{
      id:String,
      account_id:String,
      kind:#deposit | #withdrawal,
      amount:Number,
      timestamp:Number,
      status:#pending | #settled | #rejected
    }
  ],

  rules:[
    #rule{
      id:"R1",
      name:"minimum-balance",
      constraint: balance($account) >= 0usd,
      violation: #rejected{reason:"insufficient-funds"}
    },
    #rule{
      id:"R2",
      name:"maximum-withdrawal",
      constraint: amount($tx) <= 10000usd & kind($tx) = #withdrawal,
      violation: #rejected{reason:"exceeds-withdrawal-limit"}
    }
  ],

  functions:[
    #fn{
      name:"deposit",
      sig: deposit(account:@Account, amount:Number) -> #Account,
      pre: [amount > 0usd, status($account) = #active],
      body: validate(amount > 0usd)
        -> check_rules(["R1"])
        -> update($account, {balance: balance($account) + amount})
        -> emit(#Transaction{kind:#deposit, status:#settled}),
      post: balance($result) = balance($account) + amount
    },
    #fn{
      name:"withdraw",
      sig: withdraw(account:@Account, amount:Number) -> #Account | #rejected,
      pre: [amount > 0usd, status($account) = #active],
      body: validate(amount > 0usd)
        -> check_rules(["R1", "R2"])
        -> (balance($account) - amount >= 0usd
            | #rejected{reason:"insufficient-funds"})
        -> update($account, {balance: balance($account) - amount})
        -> emit(#Transaction{kind:#withdrawal, status:#settled}),
      post: balance($result) = balance($account) - amount
        | $result = #rejected
    }
  ]
}

