⟦Γ:Rules⟧{
  ∀a∈Account    : a.balance ≥ 0
  ∀a∈Account    : a.status = active ⇒ a.balance ≥ 0
  ∀r∈WithdrawRequest : r.amount > 0 ∧ r.amount ≤ 10000
  ∀r∈WithdrawRequest : r.account.balance - r.amount ≥ 0 ⇒ withdrawal_permitted(r)
  ∀r∈DepositRequest  : r.amount > 0
  ∀t∈Transaction     : t.kind = withdrawal ∧ t.result = success ⇒ t.amount ≤ 10000
  ∀a∈Account    : a.status ≠ active ⇒ ¬withdrawal_permitted(a) ∧ ¬deposit_permitted(a)
}

⟦Λ:Funcs⟧{
  deposit≜λ(a:Account, amt:Currency).
    amt > 0
    ∧ a.status = active
    → a′ ≔ a{balance ≔ a.balance + amt}
    ∧ Transaction{kind≔deposit, amount≔amt, result≔success}

  withdraw≜λ(a:Account, amt:Currency).
    amt > 0
    ∧ amt ≤ 10000
    ∧ a.status = active
    ∧ a.balance - amt ≥ 0
    → a′ ≔ a{balance ≔ a.balance - amt}
    ∧ Transaction{kind≔withdrawal, amount≔amt, result≔success}
    ∨ ¬(amt > 0 ∧ amt ≤ 10000 ∧ a.balance - amt ≥ 0)
    → Transaction{kind≔withdrawal, amount≔amt, result≔rejected}

  balance≜λ(a:Account). a.balance

  isWithdrawable≜λ(a:Account, amt:Currency).
    a.status = active
    ∧ amt > 0
    ∧ amt ≤ 10000
    ∧ a.balance ≥ amt
}

